import { notFound } from "next/navigation";
import { supabaseAdmin } from "@/app/lib/supabaseAdmin";

export default async function ShowDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;

  const { data: show, error } = await supabaseAdmin
    .from("shows")
    .select(`
      id,
      token,
      artist,
      program,
      show_date,
      weekday,
      venue,
      city,
      start_time,
      entry_time,
      created_at,
      show_details (*),
      show_files (id, file_name, file_type, storage_path),
      show_admin_notes (*)
    `)
    .eq("id", id)
    .single();

  if (error || !show) {
    notFound();
  }

  return (
    <main className="min-h-screen bg-[#fbf7ef] p-8">
      <div className="mx-auto max-w-5xl space-y-6">
        <header className="rounded-[2rem] bg-[#101014] p-10 text-white shadow-2xl">
          <p className="text-sm font-bold uppercase tracking-widest text-white/50">
            Show-Akte
          </p>
          <h1 className="mt-4 text-5xl font-black tracking-tight">
            {show.venue || "Neue Show"}
          </h1>
          <p className="mt-4 text-white/70">
            {formatDate(show.show_date)} · {show.city || "Ort offen"} ·{" "}
            {show.program || "Programm offen"}
          </p>
        </header>

        <section className="rounded-[2rem] bg-white p-6 shadow-xl shadow-black/5">
          <h2 className="text-2xl font-black">Basisdaten</h2>

          <div className="mt-6 grid gap-4 md:grid-cols-2">
            <Info label="Artist" value={show.artist} />
            <Info label="Programm" value={show.program} />
            <Info label="Datum" value={show.show_date} />
            <Info label="Wochentag" value={show.weekday} />
            <Info label="Location" value={show.venue} />
            <Info label="Stadt" value={show.city} />
            <Info label="Einlass" value={show.entry_time} />
            <Info label="Beginn" value={show.start_time} />
          </div>
        </section>
      </div>
    </main>
  );
}

function Info({ label, value }: { label: string; value?: string | null }) {
  return (
    <div className="rounded-2xl bg-[#fbf7ef] p-4">
      <p className="text-xs font-black uppercase tracking-wide text-zinc-500">
        {label}
      </p>
      <p className="mt-1 text-lg font-bold text-zinc-950">{value || "—"}</p>
    </div>
  );
}

function formatDate(date?: string | null) {
  if (!date) return "Datum offen";

  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return date;

  return d.toLocaleDateString("de-DE", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });
}